import { Component, EventEmitter, Prop, h, Event } from '@stencil/core';
import { IconLibrarySize } from '../wdpr-icon-library/wdpr-icon-library.model';

export type ModalVariant = 'default' | 'default-alt';

const modalTitleTypographyClasses =
  'text-text-heading text-heading-small font-heading-default leading-heading-small tracking--05 ' +
  'md:text-heading-medium md:leading-heading-medium ' +
  'lg:text-heading-large lg:leading-heading-large';

@Component({
  tag: 'wdpr-modal-header',
  styles: `
    :host {
      display: block;
      flex-shrink: 0;
    }
  `,
  shadow: true,
})
export class WdprModalHeader {
  @Prop() headerText: string;
  @Prop() icon: string;
  @Prop() iconSize: IconLibrarySize = 'large';
  @Prop() subtext: string;
  @Prop() showCloseIcon: boolean = true;

  /** Visual variant of the header. 'default-alt' uses alternate background color. */
  @Prop() variant: ModalVariant = 'default';

  @Event({ eventName: 'closeModal' }) close!: EventEmitter<void>;

  private getHeaderClasses(): string {
    const baseClasses = 'flex items-center justify-between px-300 py-200 border-b rounded-t-200';

    if (this.variant === 'default-alt') {
      return `${baseClasses} bg-surface-default-alt`;
    }

    return baseClasses;
  }

  render() {
    const closeButtonVariant = this.variant === 'default-alt' ? 'bgPrimary' : 'primary';

    return (
      <header class={this.getHeaderClasses()}>
        <div class="flex justify-center items-center">
          {this.icon && <wdpr-icon-library decorative icon={this.icon} size={this.iconSize} />}

          <h2 class={`${modalTitleTypographyClasses} focus:outline-none ${this.icon ? 'ml-3' : ''}`}>{this.headerText}</h2>
        </div>

        {this.subtext && <div class="flex grow justify-end body-medium text-text-disclaimer">{this.subtext}</div>}

        {this.showCloseIcon && (
          <slot name="close-icon">
            <wdpr-icon-button class="ml-175" icon-name="close-reversed" size="small" variant={closeButtonVariant} a11yLabel="Close modal" onClick={() => this.close.emit()} />
          </slot>
        )}
      </header>
    );
  }
}
